import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import Logo from './Logo';
import './Sidebar.css';

// ------------------------------------------------------------------
// Sidebar
// Props:
//   role  - 'host' | 'guest'
//   user  - { name, plan }
// ------------------------------------------------------------------

export default function Sidebar({
  role = 'host',
  user = { name: 'Amara', plan: 'Host Account' }
}) {
  const location = useLocation();
  const navigate = useNavigate();

  const hostLinks = [
    { href: '/host/dashboard', label: 'Dashboard', icon: <GridIcon /> },
    { href: '/host/home', label: 'Events', icon: <CalIcon /> },
    { href: '/host/guest-list', label: 'RSVP Manager', icon: <UsersIcon /> },
    { href: '/gallery', label: 'Gallery', icon: <GalleryIcon /> },
    { href: '/host/admin-roles', label: 'Check-In', icon: <CheckIcon /> },
  ];

  const guestLinks = [
    { href: '/guest/dashboard', label: 'Dashboard', icon: <GridIcon /> },
    { href: '/timeline', label: 'Timeline', icon: <TimelineIcon /> },
    { href: '/gallery', label: 'Gallery', icon: <GalleryIcon /> },
    { href: '/scan-qr', label: 'Scan QR', icon: <QRIcon /> },
  ];

  const links = role === 'host' ? hostLinks : guestLinks;

  return (
    <aside className="sidebar">

      {/* Logo */}
      <div className="sidebar-logo">
        <Logo />
      </div>

      {/* Navigation */}
      <nav className="sidebar-nav">
        {links.map((link, i) => {
          const isActive = location.pathname === link.href;

          return (
            <Link
              key={i}
              to={link.href}
              className={`sidebar-link${isActive ? ' active' : ''}`}
            >
              <span className="sidebar-icon">
                {link.icon}
              </span>

              {link.label}
            </Link>
          );
        })}
      </nav>

      {/* Bottom Section */}
      <div className="sidebar-bottom">

        {role === 'host' && (
          <button
            className="sidebar-link sidebar-create"
            onClick={() => navigate('/host/create-event')}
          >
            <svg
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2.5"
            >
              <circle cx="12" cy="12" r="10" />
              <path d="M12 8v8M8 12h8" />
            </svg>

            Create New Event
          </button>
        )}

        <div
          className="sidebar-user-bottom"
          onClick={() => navigate('/profile')}
          style={{ cursor: 'pointer' }}
        >
          <img
            src="/profile.png"
            alt="User avatar"
            className="sidebar-avatar-img"
          />

          <div>
            <div className="sidebar-user-name2">
              {user.name}
            </div>

            <div className="sidebar-user-plan2">
              {user.plan}
            </div>
          </div>
        </div>

      </div>
    </aside>
  );
}
